SELECT ?player ?playerLabel WHERE {
  ?player wdt:P413 wd:Q622747 .
  ?player p:P54 ?statement .
  ?statement ps:P54 wd:Q172435 .
  ?statement pq:P582 ?endTime .
  FILTER (?endTime < "2006-01-01T00:00:00Z"^^xsd:dateTime)
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER(LANG(?playerLabel) = "en") }
}
ORDER BY DESC(?endTime)
LIMIT 1

